INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline','pregnancy_care','{"حمل","رعاية الحامل","متابعة الحمل","فحوصات"}','رعاية الحمل','## رعاية الحمل\n\n**الزيارات:**\n- الثلث الأول: كل 4 أسابيع\n- الثلث الثاني: كل 2-3 أسابيع\n- الثلث الثالث: أسبوعياً\n\n**المكملات:** حمض الفوليك 5mg، حديد 60mg، كالسيوم 1000mg يومياً\n\n**⚠️ علامات الخطر:** نزيف مهبلي، صداع شديد مع تورم، قلة حركة الجنين','ar','WHO/ACOG',6,true),
('clinical_guideline','anemia_workup','{"فقر الدم","أنيميا","هيموجلوبين","حديد"}','تشخيص فقر الدم','## فقر الدم\n\n**المعايير:** Hb < 13 ذكور، < 12 إناث، < 11 حوامل\n\n**الفحوصات:** CBC، حديد، فيريتين، B12، فوليك\n\n**العلاج:**\n- نقص حديد: فيروس سلفات 200mg×2 يومياً\n- نقص B12: حقن 1000mcg أسبوعياً\n\n**⚠️ إحالة:** Hb < 7 أو أعراض قلبية','ar','WHO',6,true),
('clinical_guideline','thyroid_disorders','{"غدة درقية","ثايرويد","TSH","هرمونات"}','اضطرابات الغدة الدرقية','## الغدة الدرقية\n\n**قصور:** TSH↑ T4↓ → ليفوثيروكسين 25-50mcg\n**فرط نشاط:** TSH↓ T4↑ → كاربيمازول 15-40mg\n\n**متابعة:** TSH كل 6-8 أسابيع\n**⚠️ إحالة:** عاصفة درقية، حمل','ar','ATA',6,true),
('clinical_guideline','depression_screening','{"اكتئاب","PHQ-9","صحة نفسية","مزاج"}','فحص الاكتئاب','## PHQ-9\n\n**التصنيف:** 0-4 طبيعي، 5-9 خفيف، 10-14 متوسط، 15+ شديد\n\n**العلاج:**\n- خفيف: علاج سلوكي\n- متوسط+: فلوكسيتين 20mg + علاج نفسي\n\n**🚨 أفكار انتحارية = إحالة فورية**','ar','WHO/APA',6,true),
('clinical_guideline','pediatric_diarrhea','{"إسهال أطفال","جفاف","ORS","إماهة"}','إسهال الأطفال','## إسهال الأطفال\n\n**ORS:** <2 سنة: 50-100mL، 2-10: 100-200mL بعد كل إسهال\n**الزنك:** <6 أشهر: 10mg، >6 أشهر: 20mg لـ14 يوم\n\n**⚠️ إحالة:** دم بالبراز، جفاف شديد، <3 أشهر','ar','WHO/IMCI',6,true),
('clinical_guideline','malaria_treatment','{"ملاريا","حمى","بلازموديوم","كلوروكين"}','علاج الملاريا','## الملاريا\n\n**P. falciparum:** ACT لـ3 أيام\n**P. vivax:** كلوروكين + بريماكين 14 يوم\n**شديدة:** أرتيسونات وريدي\n\n**🚨 طوارئ:** غيبوبة، فقر دم شديد، فشل كلوي','ar','WHO',6,true),
('clinical_guideline','tb_screening','{"سل","درن","سعال مزمن","DOTS"}','فحص السل','## السل\n\n**اشتباه:** سعال >2 أسابيع، حمى ليلية، فقدان وزن\n**تشخيص:** GeneXpert، بلغم×3، أشعة صدر\n**علاج DOTS:** 2 شهر HRZE + 4 أشهر HR\n\n**متابعة:** بلغم شهر 2، 5، 6','ar','WHO',6,true),
('clinical_guideline','hiv_pep','{"HIV","PEP","وقاية","إيدز"}','الوقاية بعد التعرض HIV','## PEP\n\n**خلال 72 ساعة:** تينوفوفير/إمتريسيتابين + دولوتيجرافير لـ28 يوم\n**متابعة:** فحص HIV: فوري، 6 أسابيع، 3 أشهر، 6 أشهر\n\n**⚠️ لا يُعطى بعد 72 ساعة**','ar','WHO',6,true),
('clinical_guideline','wound_care','{"جرح","خياطة","تنظيف","عناية جروح"}','العناية بالجروح','## الجروح\n\n**تنظيف:** محلول ملحي، إزالة أجسام غريبة\n**خياطة:** جروح نظيفة <6 ساعات\n**كزاز:** جرح ملوث >5 سنوات من آخر جرعة\n\n**⚠️ إحالة:** جروح الوجه، الأوتار، الأعصاب','ar','WHO',6,true),
('clinical_guideline','burns_management','{"حروق","تبريد","سوائل","بيركلاند"}','إدارة الحروق','## الحروق\n\n**إسعاف:** تبريد بماء 20 دقيقة، لا ثلج\n**سوائل:** 4mL × وزن × نسبة الحرق\n\n**⚠️ إحالة:** >10% مساحة، الوجه/اليدين، حروق كهربائية/استنشاق','ar','WHO',6,true),
('clinical_guideline','fracture_first_aid','{"كسر","جبيرة","إسعاف","عظام"}','إسعاف الكسور','## الكسور\n\n**إسعاف أولي:**\n- تثبيت الطرف المصاب\n- كمادات باردة\n- عدم تحريك الكسر المفتوح\n\n**⚠️ إحالة فورية:** كسر مفتوح، تشوه واضح، فقدان النبض','ar','WHO',6,true),
('clinical_guideline','uti_management','{"التهاب بولي","حرقان بول","UTI","مسالك"}','التهاب المسالك البولية','## UTI\n\n**غير معقد:** نيتروفورانتوين 100mg×2 لـ5 أيام\n**بديل:** سيبروفلوكساسين 500mg×2 لـ3 أيام\n**حوامل:** أموكسيسيلين أو سيفالكسين\n\n**⚠️ إحالة:** حمى >38.5، ألم خاصرة (التهاب كلى)','ar','NICE',6,true),
('clinical_guideline','peptic_ulcer','{"قرحة معدة","حموضة","H.pylori","معدة"}','القرحة الهضمية','## القرحة الهضمية\n\n**H.pylori:** علاج ثلاثي 14 يوم\n- أوميبرازول 20mg×2\n- أموكسيسيلين 1g×2\n- كلاريثروميسين 500mg×2\n\n**⚠️ إحالة:** نزيف هضمي، فقدان وزن، عمر >55','ar','ACG',6,true),
('clinical_guideline','epilepsy_management','{"صرع","تشنج","نوبات","مضادات صرع"}','إدارة الصرع','## الصرع\n\n**الخط الأول:**\n- نوبات عامة: فالبروات 500-2000mg\n- نوبات جزئية: كاربامازبين 400-1200mg\n- حوامل: لاموتريجين\n\n**⚠️ لا توقف الدواء فجأة**','ar','ILAE',6,true),
('clinical_guideline','gout_management','{"نقرس","حمض يوريك","مفصل","ألوبيورينول"}','إدارة النقرس','## النقرس\n\n**النوبة الحادة:** كولشيسين 0.5mg×3 أو إندوميثاسين 50mg×3\n**وقاية:** ألوبيورينول 100-300mg يومياً\n**هدف:** حمض يوريك <6 mg/dL\n\n**⚠️ لا تبدأ ألوبيورينول أثناء النوبة**','ar','ACR',6,true),
('clinical_guideline','heart_failure','{"قصور قلب","ضيق تنفس","وذمة","ديجوكسين"}','قصور القلب','## قصور القلب\n\n**العلاج:**\n- ACE inhibitor: إنالابريل 2.5-20mg\n- بيتا بلوكر: بيسوبرولول 1.25-10mg\n- مدر: فوروسيمايد 20-80mg\n\n**⚠️ إحالة:** ضيق تنفس حاد، وذمة رئوية','ar','ESC/AHA',6,true),
('clinical_guideline','pneumonia_treatment','{"التهاب رئوي","ذات الرئة","سعال","حمى"}','علاج الالتهاب الرئوي','## الالتهاب الرئوي\n\n**المجتمعي (خفيف):** أموكسيسيلين 500mg×3 لـ5 أيام\n**متوسط:** أموكسيسيلين-كلافولانات + أزيثروميسين\n\n**CURB-65:** ≥3 = إدخال مستشفى\n**⚠️ طوارئ:** SpO2 <92%، تسمم دموي','ar','BTS/NICE',6,true),
('clinical_guideline','migraine_management','{"صداع نصفي","شقيقة","ميغرين","غثيان"}','إدارة الصداع النصفي','## الصداع النصفي\n\n**علاج النوبة:** سوماتريبتان 50-100mg + إيبوبروفين 400mg\n**وقاية (≥4 نوبات/شهر):** بروبرانولول 40-160mg أو أميتريبتيلين 10-50mg\n\n**⚠️ إحالة:** أسوأ صداع، أعراض عصبية جديدة','ar','NICE',6,true),
('clinical_guideline','osteoporosis','{"هشاشة عظام","كسور","كالسيوم","DEXA"}','هشاشة العظام','## هشاشة العظام\n\n**تشخيص:** DEXA T-score ≤ -2.5\n**علاج:**\n- كالسيوم 1000mg + فيتامين د 800IU يومياً\n- أليندرونات 70mg أسبوعياً\n\n**⚠️ تناول الأليندرونات صباحاً على معدة فارغة**','ar','NOF',6,true),
('clinical_guideline','iron_deficiency','{"نقص حديد","فيريتين","أنيميا صغيرة","حديد وريدي"}','نقص الحديد','## نقص الحديد\n\n**تشخيص:** فيريتين <30، MCV <80\n**علاج فموي:** فيروس سلفات 200mg×2-3 يومياً مع فيتامين C\n**وريدي:** إذا عدم تحمل فموي أو Hb <8\n\n**متابعة:** CBC بعد 4-8 أسابيع','ar','WHO',6,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide','urinary_symptoms','{"أعراض بولية","حرقان","تكرار بول","دم بالبول"}','أعراض بولية','## الأعراض البولية\n\n**حرقان + تكرار:** التهاب مسالك بولية\n**دم بالبول:** حصوات، التهاب، ورم\n**سلس بولي:** إجهادي، إلحاحي، فيضي\n**احتباس:** تضخم بروستاتا\n\n**⚠️ إحالة:** دم بالبول بدون ألم (استبعاد ورم)','ar','Custom',5,true),
('symptom_guide','skin_rash','{"طفح جلدي","حكة","أكزيما","فطريات"}','الطفح الجلدي','## الطفح الجلدي\n\n**حكة + جفاف:** أكزيما (كريم ستيرويد)\n**دائري مع حدود واضحة:** فطريات\n**فقاعات على خط واحد:** حزام ناري\n**فراشة على الوجه:** ذئبة\n\n**⚠️ طوارئ:** طفح + حمى + ألم مفاصل (فاسكيوليتيس)','ar','Custom',5,true),
('symptom_guide','eye_redness','{"احمرار عين","التهاب ملتحمة","جلوكوما","عين"}','احمرار العين','## احمرار العين\n\n**إفرازات:** التهاب ملتحمة بكتيري/فيروسي\n**حساسية للضوء + ألم:** التهاب القزحية\n**ألم شديد + رؤية ضبابية:** جلوكوما حادة\n\n**⚠️ طوارئ:** ألم + فقدان بصر = إحالة فورية لطب العيون','ar','Custom',5,true),
('symptom_guide','ear_pain','{"ألم أذن","التهاب أذن","طنين","سمع"}','ألم الأذن','## ألم الأذن\n\n**أطفال + حمى:** التهاب أذن وسطى (أموكسيسيلين)\n**بعد سباحة:** التهاب أذن خارجية (قطرة)\n**طنين + دوار:** مينيير\n**ألم مع حركة الفك:** مفصل فكي صدغي\n\n**⚠️ إحالة:** فقدان سمع مفاجئ','ar','Custom',5,true),
('symptom_guide','back_pain','{"ألم ظهر","ديسك","عرق النسا","فقرات"}','ألم الظهر','## ألم الظهر\n\n**ميكانيكي (90%):** راحة قصيرة + مسكنات + تمارين\n**عرق النسا:** ألم ممتد للساق (اختبار SLR)\n**⚠️ Red flags:**\n- ضعف في الساقين\n- سلس بولي/برازي\n- حمى + فقدان وزن\n→ **إحالة فورية (متلازمة ذيل الفرس)**','ar','NICE',5,true),
('symptom_guide','weight_loss','{"فقدان وزن","نحافة","شهية","أيض"}','فقدان الوزن غير المبرر','## فقدان الوزن (>5% في 6 أشهر)\n\n**الأسباب:**\n- فرط الغدة الدرقية\n- السكري\n- السل\n- الأورام\n- الاكتئاب\n- سوء الامتصاص\n\n**الفحوصات:** CBC، TSH، سكر، ESR، أشعة صدر\n\n**⚠️ إحالة إذا:** >10% فقدان، أعراض جهازية','ar','Custom',5,true),
('symptom_guide','fatigue','{"تعب","إرهاق","خمول","طاقة"}','التعب المزمن','## التعب\n\n**أسباب شائعة:**\n- فقر الدم (فحص CBC)\n- قصور الغدة (TSH)\n- السكري\n- الاكتئاب (PHQ-9)\n- نقص فيتامين D/B12\n- قلة النوم\n\n**فحوصات:** CBC، حديد، TSH، سكر، B12، فيتامين D\n\n**⚠️ إحالة:** تعب + فقدان وزن + تعرق ليلي','ar','Custom',5,true),
('symptom_guide','edema_swelling','{"تورم","وذمة","انتفاخ","احتباس سوائل"}','التورم والوذمة','## التورم\n\n**طرف واحد:** DVT، التهاب، إصابة\n**طرفان سفليان:** قصور قلب، كلى، كبد\n**وجه صباحاً:** مشاكل كلوية\n**حمل + تورم + ضغط:** تسمم حمل\n\n**⚠️ طوارئ:** تورم ساق مفاجئ + ألم = DVT','ar','Custom',5,true),
('symptom_guide','fever_evaluation','{"حمى","ارتفاع حرارة","عدوى","سخونة"}','تقييم الحمى','## الحمى\n\n**أسباب حسب المدة:**\n- حادة (<7 أيام): URTI، UTI، ملاريا\n- تحت حادة (7-21): حمى تيفود، خراج\n- مزمنة (>21): سل، HIV، أورام\n\n**فحوصات:** CBC، ملاريا، بول، زراعة دم\n\n**⚠️ طوارئ:** حمى + طفح + تيبس رقبة = التهاب سحايا','ar','Custom',5,true),
('symptom_guide','sore_throat','{"التهاب حلق","بلعوم","لوزتين","بلع"}','التهاب الحلق','## التهاب الحلق\n\n**فيروسي (70%):** مسكنات + سوائل\n**بكتيري (Strep):** أموكسيسيلين 500mg×3 لـ10 أيام\n**معايير Centor:** حمى، إفرازات، لا سعال، تضخم غدد\n\n**⚠️ إحالة:** صعوبة بلع/تنفس (خراج حول اللوزة)','ar','NICE',5,true),
('symptom_guide','constipation','{"إمساك","صعوبة إخراج","ملين","ألياف"}','الإمساك','## الإمساك\n\n**علاج تدريجي:**\n1. ألياف + سوائل + حركة\n2. لاكتولوز 15-30mL\n3. بيساكوديل أو سينا\n\n**⚠️ Red flags:** >50 سنة + تغير حديث، دم بالبراز، فقدان وزن → تنظير','ar','NICE',5,true),
('symptom_guide','nausea_vomiting','{"غثيان","قيء","استفراغ","معدة"}','الغثيان والقيء','## الغثيان والقيء\n\n**أسباب:**\n- هضمية: التهاب معدة، انسداد\n- حمل: الثلث الأول\n- دوائية: مضادات حيوية، كيماوي\n- عصبية: صداع نصفي\n\n**علاج:** ميتوكلوبراميد 10mg أو أوندانسيترون 4mg\n\n**⚠️ طوارئ:** قيء دموي، جفاف شديد','ar','Custom',5,true),
('symptom_guide','chest_pain_ar2','{"ألم صدر","ذبحة","قلب","تنفس"}','ألم الصدر - تفريقي','## ألم الصدر\n\n**قلبي:** ضاغط، يمتد للذراع، مع إجهاد\n**رئوي:** طعني، يزداد مع التنفس\n**هضمي:** حرقان، بعد الأكل\n**عضلي:** يزداد بالضغط والحركة\n\n**🚨 طوارئ:** ألم ضاغط + تعرق + ضيق تنفس → ECG فوري','ar','AHA',5,true),
('symptom_guide','diarrhea_adult','{"إسهال","إسهال حاد","جفاف","معوي"}','الإسهال عند البالغين','## إسهال البالغين\n\n**حاد (<14 يوم):** فيروسي غالباً → ORS + لوبراميد\n**مزمن (>14 يوم):** فحص براز + تنظير\n**دموي:** شيغيلا، أميبا → مترونيدازول\n\n**⚠️ إحالة:** جفاف شديد، دم، حمى عالية','ar','WHO',5,true),
('symptom_guide','anxiety_symptoms','{"قلق","توتر","هلع","خوف"}','أعراض القلق','## القلق\n\n**GAD-7:** >10 = قلق معتدل-شديد\n**أعراض:** خفقان، تعرق، رعشة، ضيق تنفس\n**علاج:**\n- CBT (علاج سلوكي معرفي)\n- سيرترالين 50mg أو إسيتالوبرام 10mg\n\n**🚨 نوبة هلع:** طمأنة + تنفس بطيء','ar','NICE',5,true),
('symptom_guide','dyspnea','{"ضيق تنفس","نهجان","أكسجين","رئة"}','ضيق التنفس','## ضيق التنفس\n\n**حاد:**\n- ربو: سالبيوتامول بخاخ\n- PE: تسارع + ألم صدر\n- استرواح صدري: مفاجئ + ألم\n\n**مزمن:** COPD، قصور قلب، فقر دم\n\n**⚠️ طوارئ:** SpO2 <92%، زرقة، عدم القدرة على الكلام','ar','BTS',5,true),
('symptom_guide','numbness_tingling','{"تنميل","خدر","أعصاب طرفية","وخز"}','التنميل والخدر','## التنميل\n\n**يد واحدة:** متلازمة النفق الرسغي\n**قفاز/جورب:** اعتلال أعصاب سكري\n**نصف الجسم:** سكتة دماغية\n**مع ضعف:** ضغط على العصب\n\n**🚨 تنميل مفاجئ بنصف الجسم = سكتة → طوارئ**','ar','Custom',5,true),
('symptom_guide','hair_loss','{"تساقط شعر","صلع","ثعلبة","شعر"}','تساقط الشعر','## تساقط الشعر\n\n**الأسباب:**\n- نقص حديد/فيريتين\n- اضطراب الغدة الدرقية\n- ثعلبة بقعية (مناعية)\n- صلع وراثي (أندروجيني)\n\n**فحوصات:** حديد، فيريتين، TSH، فيتامين D\n**علاج:** حسب السبب + مينوكسيديل موضعي','ar','Custom',5,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('red_flags','severe_allergic_reaction','{"حساسية شديدة","صدمة تحسسية","وذمة وعائية","أنافيلاكسيس"}','حساسية شديدة / أنافيلاكسيس','## أنافيلاكسيس\n\n**🚨 حالة طوارئ:**\n- تورم الوجه/الحلق\n- صعوبة تنفس\n- هبوط ضغط\n- طفح منتشر\n\n**العلاج الفوري:**\n- إبينفرين 0.5mg عضلي (فخذ)\n- يكرر كل 5-15 دقيقة\n- سوائل وريدية\n- هيدروكورتيزون 200mg وريدي','ar','WAO/EAACI',10,true);